CODE_EXAMPLE:
// Before
class Person {
  Telephone getTelephone() { return telephone; }
  Telephone telephone;
}

// Usage
Telephone tel = person.getTelephone();

// After
class Person {
  String getTelephoneNumber() { return telephone.getPhoneNumber(); }
  Telephone telephone;
}

// Usage
String telNumber = person.getTelephoneNumber();

UNIT_TEST_EXAMPLE:
@Test
public void testHideDelegate() {
  Person person = new Person();
  person.setTelephoneNumber("415", "9999999");

  assertEquals("4159999999", person.getTelephoneNumber());
}
